(async () => {
  if (!game.user.isGM) {
    return ui.notifications.warn("Day/Night Toggle: GM permission required.");
  }

  const scene = canvas.scene;
  if (!scene) {
    return ui.notifications.warn("Day/Night Toggle: No active scene found.");
  }

  const currentDarkness = scene.environment?.darknessLevel ?? scene.darkness ?? 0;
  const isCurrentlyNight = currentDarkness >= 0.5;
  const targetLabel    = isCurrentlyNight ? "Day" : "Night";
  const targetDarkness = isCurrentlyNight ? 0 : 0.85;
  const targetGlobalLight = isCurrentlyNight;

  let updatePayload;
  if (scene.environment !== undefined) {
    updatePayload = { "environment.darknessLevel": targetDarkness };
    if (scene.environment.globalLight !== undefined) {
      updatePayload["environment.globalLight.enabled"] = targetGlobalLight;
    }
  } else {
    updatePayload = { darkness: targetDarkness, globalLight: targetGlobalLight };
  }

  try {
    await scene.update(updatePayload, { animateDarkness: 3000 });
    ui.notifications.info(`Day/Night Toggle: Switched to ${targetLabel} (darkness: ${targetDarkness})`);
  } catch (err) {
    ui.notifications.error(`Day/Night Toggle: Failed \u2014 ${err.message}`);
  }
})();
